import numpy as np
from typing import Callable

def compare_initializations(cost_fn, num_params, noise_scales=[0.01, 0.1, 0.5, 1.0]):
    results = {}

    for scale in noise_scales:
        gradient_norms = []

        for _ in range(100):
            # Initialize with given scale
            if scale == 0:
                params = np.zeros(num_params)
            else:
                params = np.random.randn(num_params) * scale

            # Compute gradient
            grad = np.zeros(num_params)
            for i in range(num_params):
                p_plus = params.copy()
                p_plus[i] += np.pi / 2
                p_minus = params.copy()
                p_minus[i] -= np.pi / 2
                grad[i] = (cost_fn(p_plus) - cost_fn(p_minus)) / 2

            gradient_norms.append(np.linalg.norm(grad))

        results[scale] = {
            'mean_gradient_norm': np.mean(gradient_norms),
            'std_gradient_norm': np.std(gradient_norms)
        }

    # Also compare with uniform random [0, 2pi]
    gradient_norms = []
    for _ in range(100):
        params = np.random.uniform(0, 2*np.pi, num_params)
        grad = np.zeros(num_params)
        for i in range(num_params):
            p_plus = params.copy()
            p_plus[i] += np.pi / 2
            p_minus = params.copy()
            p_minus[i] -= np.pi / 2
            grad[i] = (cost_fn(p_plus) - cost_fn(p_minus)) / 2
        gradient_norms.append(np.linalg.norm(grad))

    results['uniform_random'] = {
        'mean_gradient_norm': np.mean(gradient_norms),
        'std_gradient_norm': np.std(gradient_norms)
    }

    return results

# Test
def test_cost(params):
    # Simulate quantum cost with diminishing gradients far from zero
    return np.sum(np.cos(params)) * np.exp(-np.sum(params**2) / 10)

results = compare_initializations(test_cost, 6)
for scale, data in results.items():
    print(f"Scale {scale}: norm = {data['mean_gradient_norm']:.4f}")
